&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;4.&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Rela&lt;/span&gt;&lt;/u&gt;x&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;1.&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Rele&lt;/span&gt;&lt;/u&gt;gate&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;5.&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Rep&lt;/span&gt;&lt;/u&gt;lenish&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;6.&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Resc&lt;/span&gt;&lt;/u&gt;ue&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;2.&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Reso&lt;/span&gt;&lt;/u&gt;nate&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;अतः, सही उत्तर &lt;/font&gt;&lt;/font&gt;&lt;font style=&quot;color: rgb(33, 37, 41); vertical-align: inherit;&quot;&gt;&amp;quot;&lt;/font&gt;&lt;u style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;3,4,1,5,6,2&lt;/span&gt;&lt;/u&gt;&lt;font style=&quot;color: rgb(33, 37, 41); vertical-align: inherit;&quot;&gt;&amp;quot;&amp;nbsp;&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;है।&lt;/font&gt;&lt;/font&gt;&lt;/p&gt;

questions.statement:
